import numpy as np

def search(query, df, bm25, model, index, top_k=10):
    query_vec = model.encode([query]).astype("float32")
    _, faiss_indices = index.search(query_vec, 100)
    faiss_indices = faiss_indices[0]

    bm25_scores = bm25.get_scores(query.lower().split())

    rrf_scores = np.zeros(len(df))
    for i, idx in enumerate(faiss_indices):
        rrf_scores[idx] += 1 / (60 + i + 1)

    top_bm25 = np.argsort(bm25_scores)[-100:]
    for i, idx in enumerate(top_bm25[::-1]):
        rrf_scores[idx] += 1 / (60 + i + 1)

    return df.iloc[np.argsort(rrf_scores)[-top_k:][::-1]][["title", "overview"]].to_dict("records")
